import{_ as e,c as a,o as t,b as s}from"./app.c02c7195.js";const f='{"title":"Scales","description":"","frontmatter":{"title":"Scales","subtitle":"A scale is a subset of 12 chromatic pitches","cover":"gray-notes.svg","date":"2021-08-28T00:00:00.000Z"},"headers":[],"relativePath":"theory/scales/index.md"}',o={},n=s('<p>Scales are collections of pitch classes to play together. There&#39;s a plenty of such known and used <a href="./study/">Note combinations</a>.</p><p>Five notes is enough to construct the most simple and pleasant sounding <a href="./pentatonic/">Pentatonic scales</a>. The most common scales nowadays are <a href="./diatonic/">Diatonic sets</a> of 7 notes, organized in a special way. Every note in such a scale has it&#39;s own distinct role as a <a href="./degrees/">Scale degree</a>.</p><p>Breaking the diatonic rule the modernism era has discovered all the strange <a href="./symmetrical/">Symmetrical scales</a> that bring us more complex emotional effects.</p><p>Let&#39;s not focus only on Western music theory, especially when it comes to scales. <a href="./raga/">Indian Raga</a> school has a much wider scope on note collections to be played and improvised over.</p>',4),c=[n];function i(r,l,d,h,p,_){return t(),a("div",null,c)}var u=e(o,[["render",i]]);export{f as __pageData,u as default};
